import{_ as l,W as i,X as r,a0 as e,a1 as a,Z as t,$ as n,C as o}from"./framework-d14ea875.js";const d={},p=n(`<h1 id="openlookeng" tabindex="-1"><a class="header-anchor" href="#openlookeng" aria-hidden="true">#</a> openLookeng</h1><div class="hint-container warning"><p class="hint-container-title">注意</p><p>这篇文章并不涉密。</p></div><blockquote><p>申请的是虚拟机，三台机器都是裸的，不能联网，意味着不能使用方便的包管理工具自动下载包，任何包导入都要先下载到本地，再通过xshell传上去。</p><p>我认为，机器不能上外网是可以忍受和理解的，但是我并不能接受创建的机器里面不包含一些基础的包，比如ifconfig等命令并不能正常使用。</p></blockquote><h1 id="一、裸机相关配置" tabindex="-1"><a class="header-anchor" href="#一、裸机相关配置" aria-hidden="true">#</a> 一、裸机相关配置</h1><h2 id="java" tabindex="-1"><a class="header-anchor" href="#java" aria-hidden="true">#</a> Java</h2><ol><li><p>将<code>jdk-8u341-linux-x64.tar.gz</code>下载到本地，通过xshell传到Linux的<code>/usr/local</code>路径下。</p></li><li><p>解压压缩包</p></li></ol><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">tar</span> <span class="token parameter variable">-zxvf</span> jdk-8u341-linux-x64.tar.gz
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ol start="3"><li>将解压后的jdk移动到计划安装的路径，计划安装在<code>/usr/java</code></li></ol><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">mv</span> /usr/local/jdk1.8.0_341/ /usr/java
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ol start="4"><li>设置环境变量</li></ol><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">vi</span> /etc/profile
<span class="token comment"># 在文末添加以下内容</span>
<span class="token builtin class-name">export</span> <span class="token assign-left variable">JAVA_HOME</span><span class="token operator">=</span>/usr/java/
<span class="token builtin class-name">export</span> <span class="token assign-left variable">JRE_HOME</span><span class="token operator">=</span><span class="token variable">\${JAVA_HOME}</span>/jre
<span class="token builtin class-name">export</span> <span class="token assign-left variable">LASSPATH</span><span class="token operator">=</span>.:<span class="token variable">\${JAVA_HOME}</span>/lib:<span class="token variable">\${JRE_HOME}</span>/lib:<span class="token variable">$CLASSPATH</span>
<span class="token builtin class-name">export</span> <span class="token assign-left variable">JAVA_PATH</span><span class="token operator">=</span><span class="token variable">\${JAVA_HOME}</span>/bin:<span class="token variable">\${JRE_HOME}</span>/bin
<span class="token builtin class-name">export</span> <span class="token assign-left variable"><span class="token environment constant">PATH</span></span><span class="token operator">=</span><span class="token environment constant">$PATH</span><span class="token builtin class-name">:</span><span class="token variable">\${JAVA_PATH}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="5"><li>使文件生效</li></ol><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">source</span> /etc/profile
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h1 id="二、安装openlookeng" tabindex="-1"><a class="header-anchor" href="#二、安装openlookeng" aria-hidden="true">#</a> 二、安装openLookeng</h1><p>进入<code>https://openlookeng.io/zh/download/</code>下载openLookeng Server并解压。</p><p>进入解压的根目录，创建/etc，在该目录下创建<code>node.properties</code>、<code>jvm.config</code>、<code>config.properties</code>和<code>log.properties</code>。</p><p>节点属性node.properties</p><div class="language-properties line-numbers-mode" data-ext="properties"><pre class="language-properties"><code><span class="token key attr-name">node.environment</span><span class="token punctuation">=</span><span class="token value attr-value">openLookeng</span>
<span class="token key attr-name">node.launcher-log-file</span><span class="token punctuation">=</span><span class="token value attr-value">/opt/openLookeng/hetu-server-1.9.0/log/launch.log</span>
<span class="token key attr-name">node.server-log-file</span><span class="token punctuation">=</span><span class="token value attr-value">/opt/openLookeng/hetu-server-1.9.0/log/server.log</span>
<span class="token key attr-name">catalog.config-dir</span><span class="token punctuation">=</span><span class="token value attr-value">/opt/openLookeng/hetu-server-1.9.0/etc/catalog</span>
<span class="token key attr-name">node.data-dir</span><span class="token punctuation">=</span><span class="token value attr-value">/opt/openLookeng/hetu-server-1.9.0/data</span>
<span class="token key attr-name">plugin.dir</span><span class="token punctuation">=</span><span class="token value attr-value">/opt/openLookeng/hetu-server-1.9.0/plugin</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>JVM配置jvm.config</p><div class="language-properties line-numbers-mode" data-ext="properties"><pre class="language-properties"><code>-server
-Xmx5G
<span class="token key attr-name">-XX</span><span class="token punctuation">:</span><span class="token value attr-value">-UseBiasedLocking</span>
<span class="token key attr-name">-XX</span><span class="token punctuation">:</span><span class="token value attr-value">+UseG1GC</span>
<span class="token key attr-name">-XX</span><span class="token punctuation">:</span><span class="token value attr-value">G1HeapRegionSize=32M</span>
<span class="token key attr-name">-XX</span><span class="token punctuation">:</span><span class="token value attr-value">+ExplicitGCInvokesConcurrent</span>
<span class="token key attr-name">-XX</span><span class="token punctuation">:</span><span class="token value attr-value">+ExitOnOutOfMemoryError</span>
<span class="token key attr-name">-XX</span><span class="token punctuation">:</span><span class="token value attr-value">+UseGCOverheadLimit</span>
<span class="token key attr-name">-XX</span><span class="token punctuation">:</span><span class="token value attr-value">+HeapDumpOnOutOfMemoryError</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>配置属性config.properties</p><div class="language-properties line-numbers-mode" data-ext="properties"><pre class="language-properties"><code><span class="token key attr-name">coordinator</span><span class="token punctuation">=</span><span class="token value attr-value">true</span>
<span class="token key attr-name">node-scheduler.include-coordinator</span><span class="token punctuation">=</span><span class="token value attr-value">true</span>
<span class="token key attr-name">http-server.http.port</span><span class="token punctuation">=</span><span class="token value attr-value">8080</span>
<span class="token comment">#query.max-memory=4GB</span>
<span class="token comment">#query.max-total-memory=4GB</span>
<span class="token comment">#query.max-memory-per-node=4GB</span>
<span class="token comment">#query.max-total-memory-per-node=4GB</span>
<span class="token key attr-name">discovery-server.enabled</span><span class="token punctuation">=</span><span class="token value attr-value">true</span>
<span class="token key attr-name">discovery.uri</span><span class="token punctuation">=</span><span class="token value attr-value">http://localhost:8080</span>
<span class="token key attr-name">hetu.queryeditor-ui.allow-insecure-over-http</span><span class="token punctuation">=</span><span class="token value attr-value">true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>日志属性log.properties</p><div class="language-properties line-numbers-mode" data-ext="properties"><pre class="language-properties"><code><span class="token key attr-name">io.prestosql</span><span class="token punctuation">=</span><span class="token value attr-value">INFO</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>目录属性创建在/etc下的/catalog中，&lt;datasouorce&gt;.properties。比如创建一个tpcds数据源的目录属性tpcds.properties</p><div class="language-properties line-numbers-mode" data-ext="properties"><pre class="language-properties"><code><span class="token key attr-name">connector.name</span><span class="token punctuation">=</span><span class="token value attr-value">tpcds</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>启动openLookeng。在server的目录下，执行</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>bin/launcher run
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h1 id="三、配置数据源" tabindex="-1"><a class="header-anchor" href="#三、配置数据源" aria-hidden="true">#</a> 三、配置数据源</h1><h2 id="_3-1-mysql数据源" tabindex="-1"><a class="header-anchor" href="#_3-1-mysql数据源" aria-hidden="true">#</a> 3.1 MySQL数据源</h2>`,30),c={class:"hint-container tip"},u=e("p",{class:"hint-container-title"},"MySQL在CentOS的相关安装包和环境",-1),v={href:"https://www.aliyundrive.com/s/RrHNv43a57D",target:"_blank",rel:"noopener noreferrer"},m=n(`<h3 id="_3-1-1-安装mysql" tabindex="-1"><a class="header-anchor" href="#_3-1-1-安装mysql" aria-hidden="true">#</a> 3.1.1 安装MySQL</h3><p>首先安装系统所需的依赖环境。输入指令</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>rpm -qa | grep mariadb
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>查询出内容后，将自带的环境卸载</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>rpm -e --nodeps mariadb-libs-5.5.68-1.el7.x86_64
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>查询并卸载系统老版本的MySQL（如果没有输出，则不需要卸载）</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>rpm -qa | grep mysql
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>安装libaio依赖环境和nettools依赖环境</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>rpm -ivh libaio-0.3.109-13.el7.x86_64.rpm
rpm -ivh net-tools-2.0-0.25.20131004git.el7.x86_64.rpm
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>以此输入以下指令安装MySQL：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>rpm -ivh mysql-community-common-5.7.29-1.el7.x86_64.rpm
rpm -ivh mysql-community-libs-5.7.29-1.el7.x86_64.rpm
rpm -ivh mysql-community-client-5.7.29-1.el7.x86_64.rpm
rpm -ivh mysql-community-server-5.7.29-1.el7.x86_64.rpm --nodeps --force
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>输入下面指令启动MySQL服务</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>systemctl start mysqld
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>查看MySQL服务是否启动</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>service mysqld status
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>先查看MySQL安装时随机生成的密码</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>grep &#39;temporary password&#39; /var/log/mysqld.log
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>登录MySQL，输入指令</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>mysql -u root -p
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>输入刚开始获取的随机生成的密码，登录MySQL，修改密码</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>ALTER USER &#39;root&#39;@&#39;localhost&#39; IDENTIFIED BY &#39;Abc123...&#39;;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>然后查看当前默认规则，修改校验密码策略等级，设置密码长度至少为 6，最后设置简单密码。</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>SHOW VARIABLES LIKE &#39;validate_password%&#39;;
set global validate_password_policy=LOW;
set global validate_password_length=6;
ALTER USER &#39;root&#39;@&#39;localhost&#39; IDENTIFIED BY &#39;123456&#39;;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>打开MySQL外部连接的权限</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>GRANT ALL PRIVILEGES ON *.* TO &#39;root&#39;@&#39;%&#39; IDENTIFIED BY &#39;123456&#39; WITH GRANT OPTION;
FLUSH PRIVILEGES;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>设置成功后，输入exit退出当前MySQL账户。</p><p>开放3306端口防火墙，关闭firewall防火墙指令</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment">#单次关闭</span>
<span class="token function">sudo</span> systemctl stop firewalld.service
<span class="token comment">#永久关闭</span>
<span class="token function">sudo</span> systemctl disable firewalld.service
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,28),b={href:"https://top.baidu.com/",target:"_blank",rel:"noopener noreferrer"},k=n(`<p>当前版本的MySQL，在使用group by分组时会存在报错情况，需要设置以下的MySQL模式。</p><p>编辑MySQL配置文件</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>vi /etc/my.cnf
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>在文件的最后面添加上一下内容</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>sql_mode=STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>重启MySQL服务</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>systemctl restart mysqld
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>在本地windows电脑使用navicat客户端尝试连接服务器的MySQL服务，连接成功。</p><h3 id="_3-1-2-openlookeng连接mysql数据源" tabindex="-1"><a class="header-anchor" href="#_3-1-2-openlookeng连接mysql数据源" aria-hidden="true">#</a> 3.1.2 openLookeng连接MySQL数据源</h3><p>在openLookeng的server目录中的/etc/catalog中创建MySQL数据源的properties，命名为mysql.properties，并加入以下内容。</p><div class="language-properties line-numbers-mode" data-ext="properties"><pre class="language-properties"><code><span class="token key attr-name">connector.name</span><span class="token punctuation">=</span><span class="token value attr-value">mysql</span>
<span class="token key attr-name">connection-url</span><span class="token punctuation">=</span><span class="token value attr-value">jdbc:mysql://127.0.0.1:3306</span>
<span class="token key attr-name">connection-user</span><span class="token punctuation">=</span><span class="token value attr-value">root</span>
<span class="token key attr-name">connection-password</span><span class="token punctuation">=</span><span class="token value attr-value">123456</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>启动openLookeng的server后，用浏览器访问<code>ip:8080</code>，发现mysql的catalog已加入其中。使用本地windows电脑使用navicat客户端为在MySQL中添加数据库和表，刷新网页，openLookeng加载出了新添加的数据库和表。</p><h2 id="_3-2-hive数据源" tabindex="-1"><a class="header-anchor" href="#_3-2-hive数据源" aria-hidden="true">#</a> 3.2 Hive数据源</h2><p>安装Hive数据源。</p><p>在openLookeng的server目录中的/etc/catalog中创建Hive数据源的properties，命名为hive.properties，并加入以下内容。</p><div class="language-properties line-numbers-mode" data-ext="properties"><pre class="language-properties"><code><span class="token key attr-name">connector.name</span><span class="token punctuation">=</span><span class="token value attr-value">mysql</span>
<span class="token key attr-name">connection-url</span><span class="token punctuation">=</span><span class="token value attr-value">jdbc:mysql://127.0.0.1:3306</span>
<span class="token key attr-name">connection-user</span><span class="token punctuation">=</span><span class="token value attr-value">root</span>
<span class="token key attr-name">connection-password</span><span class="token punctuation">=</span><span class="token value attr-value">123456</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>启动openLookeng的server后，用浏览器访问<code>ip:8080</code>，发现Hive的catalog已加入其中。</p><h1 id="四、客户端访问" tabindex="-1"><a class="header-anchor" href="#四、客户端访问" aria-hidden="true">#</a> 四、客户端访问</h1><h2 id="_4-1-图形界面客户端" tabindex="-1"><a class="header-anchor" href="#_4-1-图形界面客户端" aria-hidden="true">#</a> 4.1 图形界面客户端</h2><h2 id="_4-2-cli客户端" tabindex="-1"><a class="header-anchor" href="#_4-2-cli客户端" aria-hidden="true">#</a> 4.2 CLI客户端</h2><h1 id="troubleshooting" tabindex="-1"><a class="header-anchor" href="#troubleshooting" aria-hidden="true">#</a> TroubleShooting</h1>`,21);function g(h,x){const s=o("ExternalLinkIcon");return i(),r("div",null,[p,e("div",c,[u,e("p",null,[e("a",v,[a("https://www.aliyundrive.com/s/RrHNv43a57D"),t(s)]),a(" 提取码: 35vi")])]),m,e("p",null,[a("使用iptables设置开放端口："),e("a",b,[a("设置Iptables开放端口"),t(s)])]),k])}const _=l(d,[["render",g],["__file","openLookeng.html.vue"]]);export{_ as default};
